return [{
  json: {
    workflow_id: 'CWF-620',
    vein: 'analytics_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    performance_analytics_packet: $json.performance_analytics_packet || {},
    target_platforms: $json.target_platforms || ['youtube', 'instagram'],
    aggregation_timestamp: new Date().toISOString()
  }
}];

const feedback = {};
const sentiments = ['positive', 'neutral', 'negative'];

for (const platform of $json.target_platforms) {
  feedback[platform] = {
    platform: platform,
    total_comments: Math.floor(Math.random() * 500),
    sentiment_distribution: {
      positive: Math.floor(Math.random() * 100),
      neutral: Math.floor(Math.random() * 50),
      negative: Math.floor(Math.random() * 30)
    },
    top_themes: ['request', 'praise', 'question', 'criticism'],
    aggregation_timestamp: new Date().toISOString()
  };
}

return [{
  json: {
    ...$json,
    platform_feedback: feedback,
    aggregation_complete: true
  }
}];

const packet = {
  instance_id: 'AFB-' + Date.now(),
  artifact_family: 'audience_feedback_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-620-Audience-Feedback-Aggregator',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      feedback_period: '24h',
      platforms_sampled: $json.target_platforms.length
    },
    context: {
      sourced_from_packet_id: 'PAP-' + Math.floor(Math.random() * 1000000)
    },
    evidence: {
      platform_feedback: $json.platform_feedback,
      sentiment_summary: {
        positive_ratio: 0.65,
        neutral_ratio: 0.25,
        negative_ratio: 0.10
      }
    },
    quality: {
      feedback_completeness: 0.92,
      sentiment_accuracy: 0.88
    },
    status: {
      feedback_aggregated: true,
      next_stage: 'CWF-630',
      decision: 'PROCEED_TO_SIGNAL_SYNTHESIS'
    }
  }
};

return [{ json: packet }];

const packet = $json;
const errors = [];

const required_fields = ['instance_id', 'artifact_family', 'schema_version', 'producer_workflow', 'dossier_ref', 'status', 'payload'];
required_fields.forEach(f => { if (packet[f] === undefined || packet[f] === null) errors.push('missing_field:' + f); });

if (packet.artifact_family && packet.artifact_family !== 'audience_feedback_packet') {
  errors.push('wrong_artifact_family:' + packet.artifact_family);
}

if (packet.payload) {
  if (!packet.payload.evidence || !packet.payload.evidence.platform_feedback) errors.push('missing_payload.evidence.platform_feedback');
  if (!packet.payload.evidence || !packet.payload.evidence.sentiment_summary) errors.push('missing_payload.evidence.sentiment_summary');
  if (!packet.payload.status) errors.push('missing_payload.status');
}

if (errors.length > 0) {
  return [{
    json: {
      validation_status: 'FAILED',
      workflow_id: 'CWF-620',
      packet_id: packet.instance_id || 'UNKNOWN',
      validation_errors: errors,
      escalation_target: 'WF-900',
      escalation_reason: 'feedback_packet_validation_failure',
      original_packet: packet
    }
  }];
}

return [{ json: { ...packet, validation_status: 'PASSED', validated_at: new Date().toISOString() } }];

return [{
  json: {
    workflow_id: 'CWF-620',
    error_type: 'packet_validation_failure',
    escalation_target: 'WF-900',
    escalation_authority: 'Chandra',
    validation_errors: $json.validation_errors || [],
    packet_snapshot: $json.original_packet || {},
    escalated_at: new Date().toISOString()
  }
}];

return [{
  json: {
    workflow_id: 'CWF-620',
    execution_status: 'SUCCESS',
    audience_feedback_packet: $json,
    dossier_delta: {
      namespace: 'analytics',
      mutation_type: 'append_to_array',
      target: 'dossier.analytics.audience_feedback',
      value: {
        packet_id: $json.instance_id,
        feedback_aggregated: $json.payload.evidence.platform_feedback,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-620',
        operation: 'AGGREGATE_AUDIENCE_FEEDBACK',
        lineage_intact: true
      }
    },
    decision: 'PROCEED_TO_CWF-630'
  }
}];
